// MARK: - Usage Example

class PasswordManager {
    private let storage = PasswordStorageUtility()
    
    func registerUser(username: String, password: String) -> Bool {
        // Validate password strength before storing
        guard isPasswordStrong(password) else {
            print("Password does not meet strength requirements")
            return false
        }
        
        return storage.storePassword(username: username, password: password)
    }
    
    func authenticateUser(username: String, password: String) -> Bool {
        return storage.verifyPassword(username: username, password: password)
    }
    
    func changePassword(username: String, oldPassword: String, newPassword: String) -> Bool {
        guard isPasswordStrong(newPassword) else {
            print("New password does not meet strength requirements")
            return false
        }
        
        return storage.updatePassword(username: username, oldPassword: oldPassword, newPassword: newPassword)
    }
    
    func removeUser(username: String) -> Bool {
        return storage.deletePassword(username: username)
    }
    
    private func isPasswordStrong(_ password: String) -> Bool {
        // Minimum 8 characters
        guard password.count >= 8 else {
            return false
        }
        
        // Check for at least one uppercase, one lowercase, one digit
        let uppercaseRegex = ".*[A-Z]+.*"
        let lowercaseRegex = ".*[a-z]+.*"
        let digitRegex = ".*[0-9]+.*"
        
        let hasUppercase = password.range(of: uppercaseRegex, options: .regularExpression) != nil
        let hasLowercase = password.range(of: lowercaseRegex, options: .regularExpression) != nil
        let hasDigit = password.range(of: digitRegex, options: .regularExpression) != nil
        
        return hasUppercase && hasLowercase && hasDigit
    }
}

